const a="";async function o(t,e){const s=await fetch(a+t,{headers:{"Content-Type":"application/json"},...e});if(!s.ok){const r=await s.text().catch(()=>"");let n;try{n=JSON.parse(r).error||s.statusText}catch{n=r||s.statusText}throw new Error(n)}return s.json()}const i={get:t=>o(t),post:(t,e)=>o(t,{method:"POST",body:JSON.stringify(e)}),put:(t,e)=>o(t,{method:"PUT",body:JSON.stringify(e)}),delete:(t,e)=>o(t,{method:"DELETE",body:e?JSON.stringify(e):void 0})};export{i as a};
